-- Enable extensions
create extension if not exists "uuid-ossp";
create extension if not exists "pgcrypto";

-- ============================================================================
-- 0. ROLES & PROFILES
-- ============================================================================
do $$ begin
  create type public.user_role as enum ('admin',       -- Full akses (Alfatehan + Kepala SPPG)
  'operator',    -- Harian: stok, PO, GRN, invoice, receipt foto
  'ahli_gizi',   -- Menu master, BOM, kalender, custom menu
  'supplier',    -- Read PO/GRN/Invoice milik sendiri, update status GRN
  'viewer'       -- Read-only: WFP PIC, auditor);
exception when duplicate_object then null;
end $$;

create table if not exists public.profiles (
  id uuid primary key references auth.users(id) on delete cascade,
  email text not null unique,
  full_name text,
  role public.user_role not null default 'viewer',
  supplier_id text,                       -- Jika role=supplier, link ke suppliers.id
  phone text,
  active boolean not null default true,
  created_at timestamptz not null default now(),
  invited_by uuid references auth.users(id),
  last_login_at timestamptz
);
create index if not exists idx_profiles_role on public.profiles(role);
create index if not exists idx_profiles_supplier on public.profiles(supplier_id) where supplier_id is not null;

-- Invite flow (admin-only create, token disumption saat magic-link dipakai)
create table if not exists public.invites (
  id uuid primary key default uuid_generate_v4(),
  email text not null,
  role public.user_role not null,
  supplier_id text,
  token text not null unique default encode(gen_random_bytes(24),'hex'),
  created_by uuid references auth.users(id),
  created_at timestamptz not null default now(),
  expires_at timestamptz not null default (now() + interval '7 days'),
  used_at timestamptz,
  used_by uuid references auth.users(id)
);
create index if not exists idx_invites_email on public.invites(lower(email));
create index if not exists idx_invites_token on public.invites(token);

